#include <stdio.h>

typedef struct {
    int process_id;
    int allocated_frames;
    double fault_rate;
    int page_faults;
    int references;
} Process;

#define UPPER_THRESHOLD 0.1  // 10% fault rate
#define LOWER_THRESHOLD 0.01 // 1% fault rate
#define FRAME_ADJUSTMENT 5

void adjustAllocation(Process *p, int available_frames) {
    // Calculate fault rate
    p->fault_rate = (double)p->page_faults / p->references;

    // Adjust based on thresholds
    if (p->fault_rate > UPPER_THRESHOLD) {
        // Need more frames
        if (available_frames >= FRAME_ADJUSTMENT) {
            p->allocated_frames += FRAME_ADJUSTMENT;
            available_frames -= FRAME_ADJUSTMENT;
            printf("Process %d: High fault rate (%.2f), +%d frames\n",
                   p->process_id, p->fault_rate * 100, FRAME_ADJUSTMENT);
        }
    } else if (p->fault_rate < LOWER_THRESHOLD && p->allocated_frames > 1) {
        // Can give up some frames
        p->allocated_frames -= FRAME_ADJUSTMENT;
        available_frames += FRAME_ADJUSTMENT;
        printf("Process %d: Low fault rate (%.2f), -%d frames\n",
               p->process_id, p->fault_rate * 100, FRAME_ADJUSTMENT);
    }

    // Reset counters after adjustment
    p->page_faults = 0;
    p->references = 0;
}

int main() {
    Process p = {1, 10, 0.0, 0, 0};
    // Simulate some page references and faults
    p.page_faults = 15;
    p.references = 100;

    adjustAllocation(&p, 90);
    return 0;
}

import java.util.*;

public class WorkingSetAllocation {
    private int windowSize;  // Δ - working set window
    private Map<Integer, Set<Integer>> pageHistory;
    private Map<Integer, Integer> allocatedFrames;

    public WorkingSetAllocation(int windowSize) {
        this.windowSize = windowSize;
        this.pageHistory = new HashMap<>();
        this.allocatedFrames = new HashMap<>();
    }

    // Record a page reference
    public void recordReference(int processId, int pageNumber) {
        pageHistory.computeIfAbsent(processId, k -> new LinkedHashSet<>());
        Set<Integer> history = pageHistory.get(processId);

        history.add(pageNumber);

        // Keep only last 'windowSize' unique references
        if (history.size() > windowSize) {
            Iterator<Integer> it = history.iterator();
            it.next();  // Remove oldest
            it.remove();
        }
    }

    // Calculate working set size for a process
    public int getWorkingSetSize(int processId) {
        Set<Integer> ws = pageHistory.get(processId);
        return (ws != null) ? ws.size() : 0;
    }

    // Allocate frames based on working set
    public int allocateFrames(int processId, int availableFrames) {
        int wsSize = getWorkingSetSize(processId);

        // Allocate at least working set size, or available/numProcesses
        int allocation = Math.max(wsSize, availableFrames / 10); // minimum

        allocatedFrames.put(processId, allocation);
        return allocation;
    }

    public static void main(String[] args) {
        WorkingSetAllocation allocator = new WorkingSetAllocation(5);

        // Simulate process references
        int pid = 1;
        int[] refs = {1, 2, 3, 4, 5, 1, 2, 6, 7, 1};

        for (int page : refs) {
            allocator.recordReference(pid, page);
        }

        System.out.println("Working set size: " + allocator.getWorkingSetSize(pid));
        System.out.println("Allocated frames: " + allocator.allocateFrames(pid, 100));
    }
}
